import{_ as a,o as s,c as e,ag as t}from"./chunks/framework.CvgP6Fyv.js";const g=JSON.parse('{"title":"Codebase Analysis","description":"Phân tích cấu trúc thư mục, kiến trúc và test coverage của HappyAgent","frontmatter":{"title":"Codebase Analysis","description":"Phân tích cấu trúc thư mục, kiến trúc và test coverage của HappyAgent","robots":"index, follow"},"headers":[],"relativePath":"analysis.md","filePath":"analysis.md"}'),o={name:"analysis.md"};function c(i,n,r,l,p,h){return s(),e("div",null,[...n[0]||(n[0]=[t(`<h1 id="phan-tich-system-codebase" tabindex="-1">Phân tích System &amp; Codebase <a class="header-anchor" href="#phan-tich-system-codebase" aria-label="Permalink to &quot;Phân tích System &amp; Codebase&quot;">​</a></h1><div class="info custom-block"><p class="custom-block-title">Tổng quan</p><p><strong>Hệ sinh thái:</strong> Node.js, Shell Script <strong>Công nghệ lõi:</strong> Playwright (Web Automation), Winston (Logging), AI CLI Agent <strong>Kiến trúc:</strong> Modular, Pipeline theo Hướng sự kiện (Fail -&gt; Heal)</p></div><h2 id="_1-cau-truc-thu-muc-directory-structure" tabindex="-1">1. Cấu trúc thư mục (Directory Structure) <a class="header-anchor" href="#_1-cau-truc-thu-muc-directory-structure" aria-label="Permalink to &quot;1. Cấu trúc thư mục (Directory Structure)&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>HappyAgent/</span></span>
<span class="line"><span>├── config/                  # Configuration Layer</span></span>
<span class="line"><span>│   ├── creators.csv         # Danh sách Creators</span></span>
<span class="line"><span>│   ├── message-template.json# Template thư mời</span></span>
<span class="line"><span>│   └── profiles.json        # Cấu hình danh sách Chrome Profile</span></span>
<span class="line"><span>├── data/</span></span>
<span class="line"><span>│   └── errors/              # Dữ liệu xuất ra (Screenshot, DOM, Logs) cho Healer</span></span>
<span class="line"><span>├── docs/                    # Tài liệu dự án (bạn đang đọc thư mục này)</span></span>
<span class="line"><span>├── openspec/                # Thiết kế hệ thống (Proposal)</span></span>
<span class="line"><span>├── scripts/</span></span>
<span class="line"><span>│   └── run.sh               # Luồng điều phối cấp cao nhất (Bash Loop)</span></span>
<span class="line"><span>├── skills/</span></span>
<span class="line"><span>│   └── tiktok-healer.md     # Prompt guidelines cho AI Agent</span></span>
<span class="line"><span>└── src/                     # Core Business Logic</span></span>
<span class="line"><span>    ├── healer.js            # Tác vụ AI sửa selector</span></span>
<span class="line"><span>    ├── orchestrator.js      # Luồng Node.js quản lý tiến trình</span></span>
<span class="line"><span>    ├── runner.js            # Playwright automation engine</span></span>
<span class="line"><span>    ├── tracer.js            # Capture lỗi xuất DOM và logs</span></span>
<span class="line"><span>    └── utils/</span></span>
<span class="line"><span>        ├── csv-reader.js    # Modun đọc/ghi DB dạng CSV</span></span>
<span class="line"><span>        ├── logger.js        # Logging output chuẩn hóa Winston</span></span>
<span class="line"><span>        └── selectors.js     # Single Source of Truth cho các CSS Selectors</span></span></code></pre></div><h2 id="_2-dependencies-overview" tabindex="-1">2. Dependencies Overview <a class="header-anchor" href="#_2-dependencies-overview" aria-label="Permalink to &quot;2. Dependencies Overview&quot;">​</a></h2><p>Các thư viện chính được sử dụng (trong <code>package.json</code>):</p><ul><li><strong><code>playwright</code></strong>: Lõi tự động hoá trình duyệt Chromium.</li><li><strong><code>winston</code></strong>: Tiêu chuẩn hoá logging, ghi log lỗi ra file JSON phục vụ cho Tracer.</li><li><strong><code>csv-parse/sync</code> &amp; <code>csv-stringify/sync</code></strong>: Quản lý State/DB ngay trên file CSV, theo dõi tiến độ gửi thư mời.</li><li><strong><code>dotenv</code></strong>: Load environment variables từ <code>.env</code>.</li></ul><h2 id="_3-quan-ly-trang-thai-state-management" tabindex="-1">3. Quản lý trạng thái (State Management) <a class="header-anchor" href="#_3-quan-ly-trang-thai-state-management" aria-label="Permalink to &quot;3. Quản lý trạng thái (State Management)&quot;">​</a></h2><p>Dự án không sử dụng Database Relational (MySQL/PostgreSQL) vì yêu cầu tính chất gọn nhẹ của Native Script. Thay vào đó:</p><ol><li><strong>Dữ liệu đầu vào và Trạng thái</strong>: Lưu trên file <code>config/creators.csv</code>. Dữ liệu liên tục được cập nhật cột <code>status</code>, <code>invited_at</code>. Cột status gồm: <code>pending</code>, <code>invited</code>, <code>error_reason</code>.</li><li><strong>Dữ liệu lỗi (Tracer)</strong>: Xuất ra các file <code>.html</code>, <code>.png</code>, <code>.json</code> tĩnh trong thư mục <code>data/errors/</code>. Healer sẽ bốc tách file json mới nhất để đẩy vào AI System.</li></ol><h2 id="_4-test-coverage" tabindex="-1">4. Test Coverage <a class="header-anchor" href="#_4-test-coverage" aria-label="Permalink to &quot;4. Test Coverage&quot;">​</a></h2><ul><li>Hệ thống hỗ trợ cờ <code>DRY_RUN=true</code> trong môi trường giả lập, cho phép test toàn bộ tiến trình điều khiển UI mà không nhấn vào nút Gửi thật sự (Send Invite API của Tiktok sẽ không bị kích hoạt).</li><li>Pipeline kiểm thử bao gồm việc tự động cập nhật <code>.csv</code> khi Dry Run hoàn thành mà không vướng phải <code>TimeoutError</code>.</li></ul>`,12)])])}const u=a(o,[["render",c]]);export{g as __pageData,u as default};
